def solve(n: int, k: int) -> int:
    if k == 0:
        return 1 if n >= 1 else 0

    # Precompute the popcount-depth for numbers up to a certain limit (since k <=5, max depth is 5)
    max_num = 60  # 2^60 is way larger than 1e15, and popcount-depth for 2^60 is 1 (60 in binary has popcount 2, then 1)
    depth = [0] * (max_num + 1)

    for i in range(1, max_num + 1):
        x = i
        d = 0
        while x != 1:
            x = bin(x).count('1')
            d += 1
        depth[i] = d

    # Now, we need to find numbers x in [1, n] such that their popcount-depth is k
    # To compute this efficiently, we can use digit DP to count numbers x where the popcount of x has depth (k-1)
    # Because the depth of x is 1 + depth of popcount(x)

    from functools import lru_cache

    def count_numbers_with_popcount_p(target_p: int) -> int:
        # Count numbers x in [1, n] where popcount(x) == target_p
        s = bin(n)[2:]
        m = len(s)

        @lru_cache(maxsize=None)
        def dp(pos: int, cnt: int, tight: bool) -> int:
            if pos == m:
                return 1 if cnt == target_p else 0
            limit = int(s[pos]) if tight else 1
            total = 0
            for d in range(0, limit + 1):
                new_tight = tight and (d == limit)
                new_cnt = cnt + (d == 1)
                total += dp(pos + 1, new_cnt, new_tight)
            return total
        return dp(0, 0, True)

    if k == 1:
        # Numbers x where popcount(x) == 1 (i.e., powers of 2) and x != 1 (since depth of 1 is 0)
        # So x must be 2^m where m >=1, and 2^m <=n
        # The count is floor(log2(n))
        return count_numbers_with_popcount_p(1) - 1  # subtract x=1 (popcount 1, depth 0)
    else:
        # Find all p where depth[p] == k-1, then count numbers x with popcount(x) == p
        total = 0
        for p in range(1, max_num + 1):
            if depth[p] == k - 1:
                total += count_numbers_with_popcount_p(p)
        return total
